PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "joinRecordDB" (`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL, `user_created` char(36) NULL, `date_created` datetime NULL, `user_updated` char(36) NULL, `date_updated` datetime NULL, `registrationId` integer NULL DEFAULT '-1', `activityId` integer NULL DEFAULT '-1', `state` varchar(255) NULL, `items` json NULL DEFAULT '[]', `totalAmount` integer NULL DEFAULT '0', `discountAmount` integer NULL DEFAULT '0', `finalAmount` integer NULL DEFAULT '0', `paidAmount` integer NULL DEFAULT '0', `needReceipt` varchar(255) NULL DEFAULT '0', `receiptNumber` varchar(255) NULL, `receiptIssued` varchar(255) NULL DEFAULT null, `receiptIssuedAt` varchar(255) NULL, `receiptIssuedBy` varchar(255) NULL, `accountingState` varchar(255) NULL, `accountingDate` varchar(255) NULL, `accountingBy` varchar(255) NULL, `accountingNotes` varchar(255) NULL, `paymentState` varchar(255) NULL, `paymentMethod` varchar(255) NULL, `paymentDate` varchar(255) NULL, `paymentNotes` varchar(255) NULL, `notes` varchar(255) NULL, `createdAt` varchar(255) NULL, `updatedAt` varchar(255) NULL, `contact` json NULL, `receiptId` integer null default '-1', CONSTRAINT `joinRecorddb_user_created_foreign` FOREIGN KEY (`user_created`) REFERENCES `directus_users` (`id`), CONSTRAINT `joinRecorddb_user_updated_foreign` FOREIGN KEY (`user_updated`) REFERENCES `directus_users` (`id`));
COMMIT;
